import{_ as e,o as d,c as l,ag as a}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Editor 别名 | Dotfiles (ZH)","titleTemplate":":title","description":"Neovim、VS Code、Vim、Nano、Emacs 和 Sublime Text 的 shell 别名。使用通用快捷方式更快地编辑文件。","frontmatter":{"title":"Editor 别名 | Dotfiles","description":"Neovim、VS Code、Vim、Nano、Emacs 和 Sublime Text 的 shell 别名。使用通用快捷方式更快地编辑文件。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Editor 别名 preview","canonical":"/zh/aliases/editor/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Editor 别名","pageType":"docs","schemaType":"WebPage","metaTitle":"Editor 别名 - Dotfiles (CN)","permalink":"/zh/aliases/editor/","sidebar":true,"meta":[{"name":"keywords","content":"编辑器别名, neovim, vim, vscode, nano, emacs, sublime text, shell 快捷方式, dotfiles"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Neovim、VS Code、Vim、Nano、Emacs 和 Sublime Text 的 shell 别名。使用通用快捷方式更快地编辑文件。"},{"name":"twitter:title","content":"Editor 别名 - Dotfiles"},{"name":"og:title","content":"Editor 别名 - Dotfiles"},{"name":"og:description","content":"Neovim、VS Code、Vim、Nano、Emacs 和 Sublime Text 的 shell 别名。使用通用快捷方式更快地编辑文件。"},{"name":"og:image:alt","content":"Dotfiles - 为你的 Shell 生活精心设计"},{"name":"og:locale","content":"zh_CN"}]},"headers":[],"relativePath":"zh/aliases/editor/index.md","filePath":"zh/aliases/editor/index.md","lastUpdated":1773010926000}'),i={name:"zh/aliases/editor/index.md"};function o(r,t,s,n,c,f){return d(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="editor-别名" tabindex="-1">Editor 别名 <a class="header-anchor" href="#editor-别名" aria-label="Permalink to &quot;Editor 别名&quot;">​</a></h1><p>启动和配置首选文本编辑器的快捷方式。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>编辑器别名为多个应用程序提供了统一的文本编辑界面。定义在 <code>editor.aliases.sh</code> 中，由 chezmoi 自动加载，这些快捷方式与 <code>editor.sh</code> 协同工作，检测并配置系统上可用的最佳编辑器。</p><p>系统支持 Neovim、Visual Studio Code、Vim、Nano、Emacs、Sublime Text 和 Atom。通用别名适应任何活动编辑器，而专用别名提供编辑器特定的功能。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><h3 id="通用别名" tabindex="-1">通用别名 <a class="header-anchor" href="#通用别名" aria-label="Permalink to &quot;通用别名&quot;">​</a></h3><p>这些别名适用于 <code>editor.sh</code> 配置的任何编辑器。</p><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>e</code></td><td style="text-align:left;">快速编辑命令</td></tr><tr><td style="text-align:left;"><code>edit</code></td><td style="text-align:left;">标准编辑命令</td></tr><tr><td style="text-align:left;"><code>editor</code></td><td style="text-align:left;">完整编辑器命令</td></tr><tr><td style="text-align:left;"><code>mate</code></td><td style="text-align:left;">TextMate 风格命令</td></tr><tr><td style="text-align:left;"><code>n</code></td><td style="text-align:left;">短编辑别名</td></tr><tr><td style="text-align:left;"><code>v</code></td><td style="text-align:left;">Vim 风格编辑别名</td></tr></tbody></table><h3 id="neovim-别名" tabindex="-1">Neovim 别名 <a class="header-anchor" href="#neovim-别名" aria-label="Permalink to &quot;Neovim 别名&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>vi</code></td><td style="text-align:left;">重定向到 Neovim</td></tr><tr><td style="text-align:left;"><code>vim</code></td><td style="text-align:left;">重定向到 Neovim</td></tr><tr><td style="text-align:left;"><code>nvimrc</code></td><td style="text-align:left;">编辑 Neovim Vimscript 配置</td></tr><tr><td style="text-align:left;"><code>nvimlua</code></td><td style="text-align:left;">编辑 Neovim Lua 配置</td></tr><tr><td style="text-align:left;"><code>nvimconf</code></td><td style="text-align:left;">打开 Neovim 配置目录</td></tr></tbody></table><h3 id="visual-studio-code-别名" tabindex="-1">Visual Studio Code 别名 <a class="header-anchor" href="#visual-studio-code-别名" aria-label="Permalink to &quot;Visual Studio Code 别名&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>vsc</code></td><td style="text-align:left;">启动 VS Code</td></tr><tr><td style="text-align:left;"><code>vsca</code></td><td style="text-align:left;">将文件夹添加到当前窗口</td></tr><tr><td style="text-align:left;"><code>vscd</code></td><td style="text-align:left;">比较两个文件</td></tr><tr><td style="text-align:left;"><code>vscn</code></td><td style="text-align:left;">打开新窗口</td></tr><tr><td style="text-align:left;"><code>vscr</code></td><td style="text-align:left;">复用窗口打开文件</td></tr><tr><td style="text-align:left;"><code>vscex</code></td><td style="text-align:left;">安装 VS Code 扩展</td></tr><tr><td style="text-align:left;"><code>vsclist</code></td><td style="text-align:left;">列出已安装的扩展</td></tr></tbody></table><h3 id="配置编辑" tabindex="-1">配置编辑 <a class="header-anchor" href="#配置编辑" aria-label="Permalink to &quot;配置编辑&quot;">​</a></h3><p><code>editrc</code> 函数提供对常用配置文件的快速访问。</p><table tabindex="0"><thead><tr><th style="text-align:left;">命令</th><th style="text-align:left;">目标文件</th></tr></thead><tbody><tr><td style="text-align:left;"><code>editrc bash</code></td><td style="text-align:left;"><code>~/.bashrc</code></td></tr><tr><td style="text-align:left;"><code>editrc zsh</code></td><td style="text-align:left;"><code>~/.zshrc</code></td></tr><tr><td style="text-align:left;"><code>editrc vim</code></td><td style="text-align:left;"><code>~/.vimrc</code></td></tr><tr><td style="text-align:left;"><code>editrc nvim</code></td><td style="text-align:left;">Neovim init 文件</td></tr><tr><td style="text-align:left;"><code>editrc tmux</code></td><td style="text-align:left;"><code>~/.tmux.conf</code></td></tr><tr><td style="text-align:left;"><code>editrc git</code></td><td style="text-align:left;"><code>~/.gitconfig</code></td></tr><tr><td style="text-align:left;"><code>editrc ssh</code></td><td style="text-align:left;"><code>~/.ssh/config</code></td></tr></tbody></table>',16)])])}const m=e(i,[["render",o]]);export{h as __pageData,m as default};
